// ── Sector Templates ──────────────────────────────────────────────────────────
//
// Each sector defines a default department structure and, per department, a
// default KPI set. KPIs follow ActLedger's 5-layer global template:
//
//   1. PERFORMANCE   - output, completion, speed, efficiency
//   2. QUALITY       - defect rate, first pass yield, accuracy, satisfaction
//   3. TIME          - response time, cycle time, closure time, schedule adherence
//   4. RISK          - blockers, escalations, downtime, SLA breach
//   5. AI INSIGHT    - root cause cluster, anomaly score, predictive risk
//
// Labels are bilingual (TR + EN). The frontend renders one based on the active
// language; the backend stores both so a sector can be applied regardless of
// the picker's locale at apply-time.
//
// Adding a new sector: append to SECTOR_TEMPLATES with the same shape.

export type KpiLayer = 'performance' | 'quality' | 'time' | 'risk' | 'ai_insight'

export interface KpiTemplate {
  /** Stable code, snake_case, used as the DB row's `code` (unique per dept) */
  code: string
  layer: KpiLayer
  /** Display label - bilingual */
  label: { tr: string; en: string }
  /** Optional unit hint shown next to value: "%", "saat", "adet", ... */
  unit?: string
  /** Optional short description shown under the KPI */
  description?: { tr: string; en: string }
}

export interface DepartmentTemplate {
  /** Stable code, UPPER_SNAKE, used as Department.code (unique per company) */
  code: string
  /** Display name - bilingual */
  name: { tr: string; en: string }
  /** Tailwind-friendly hex color for the department badge */
  color: string
  /** Short description shown in the sector preview UI */
  description?: { tr: string; en: string }
  /** Default KPI set */
  kpis: KpiTemplate[]
}

export interface SectorTemplate {
  id: string
  name: { tr: string; en: string }
  icon: string
  description: { tr: string; en: string }
  departments: DepartmentTemplate[]
}

