export const SECTOR_TEMPLATES: Record<string, SectorTemplate> = {
  manufacturing: MANUFACTURING,
  fmcg: FMCG,
  horeca: HORECA,
  healthcare: HEALTHCARE,
  energy: ENERGY,
  retail: RETAIL,
  logistics: LOGISTICS,
  construction: CONSTRUCTION,
  municipality: MUNICIPALITY,
  commerce: COMMERCE,
  finance: FINANCE_SECTOR,
  media: MEDIA,
  transportation: TRANSPORTATION,
  it: IT_SECTOR,
  startup: STARTUP,
}

export function getSectorTemplate(id: string): SectorTemplate | null {
  return SECTOR_TEMPLATES[id] ?? null
}

